I modified loadEnvVars as a work around for now:

```
  loadEnvVars() {
    let dropObjects = function(vars) {
      return _.pickBy(vars, (v, k) => {
        return typeof v != 'object'
      })
    }
    const providerEnvVars = this.serverless.service.provider.environment || {};
    _.merge(process.env, dropObjects(providerEnvVars));

    _.each(this.serverless.service.functions, (func) => {
      if (func.handler == 'wsgi.handler') {
        const functionEnvVars = func.environment || {};
        _.merge(process.env, dropObjects(functionEnvVars));
      }
    });

    return BbPromise.resolve();
  }
```

