Our data sets are so big that without streaming the browser / server times out, so we did this hacky approach:

```
class JSONApiCSVRenderer(csv_renderers.CSVStreamingRenderer):
    def flatten_list(self, l):
        return {'items': ','.join(str(pk) for pk in l)}

    def render(self, data, media_type=None, renderer_context={}):
        if 'queryset' not in data:
            return data

        csv_buffer = Echo()
        csv_writer = csv.writer(csv_buffer)
        if data['queryset'].count() > 0:
            yield csv_writer.writerow([
                elem[0]
                for elem
                in self.flatten_data([data['serializer'](data['queryset'].first()).data])[0].items()
            ])

        generator = (
            self.flatten_data([data['serializer'](item).data])[0] for item in data['queryset']
        )
        for row in generator:
            yield csv_writer.writerow([
                elem.encode('utf-8') if isinstance(elem, text_type) and PY2 else elem
                for _, elem in row.items()
            ])


class V2Mixin(object):
    pagination_class = V2Pagination
    parser_classes = (
        rest_framework_json_api.parsers.JSONParser,
        rest_framework.parsers.FormParser,
        rest_framework.parsers.MultiPartParser,
    )
    renderer_classes = (
        rest_framework_json_api.renderers.JSONRenderer,
        rest_framework.renderers.BrowsableAPIRenderer,
        JSONApiCSVRenderer,
    )
    metadata_class = rest_framework_json_api.metadata.JSONAPIMetadata

    def list(self, request, *args, **kwargs):
        queryset = self.filter_queryset(self.get_queryset())

        if isinstance(request.accepted_renderer, JSONApiCSVRenderer):
            return StreamingHttpResponse(request.accepted_renderer.render({
                'queryset': queryset,
                'serializer': self.get_serializer_class(),
            }))
        else:
            page = self.paginate_queryset(queryset)
            if page is not None:
                serializer = self.get_serializer(page, many=True)
                data = serializer.data
                return self.get_paginated_response(data)
            else:
                serializer = self.get_serializer(queryset, many=True)
                return Response(serializer.data)
```

I can replicate this. A workaround that works is to instantiate each `Serializer` every time it is passed to `GenericRelatedField`:

```python
class TimelineSerializer(serializers.ModelSerializer):
    actor = GenericRelatedField({
        Tweet: TweetSerializer(),
        ReTweet: ReTweetSerializer(),
        User: PlainUserSerializer(),
    })
    action_object = GenericRelatedField({
        Tweet: TweetSerializer(),
        ReTweet: ReTweetSerializer(),
        User: PlainUserSerializer(),
    })
    target = GenericRelatedField({
        Tweet: TweetSerializer(),
        ReTweet: ReTweetSerializer(),
        User: PlainUserSerializer(),
    })
```

instead of:

```python
class TimelineSerializer(serializers.ModelSerializer):
    __basic_fields = {
        Tweet: TweetSerializer(),
        ReTweet: ReTweetSerializer(),
        User: PlainUserSerializer(),
    }
    actor = GenericRelatedField(__basic_fields)
    # Can use only 1 `GenericRelatedField` per `serializer`
    action_object = GenericRelatedField(__basic_fields)
    target = GenericRelatedField(__basic_fields)
```

